cd /workspace/data; python3 - <<'EOF'
lines=[l.rstrip('\n') for l in open('kon.trn')]
from collections import defaultdict
rows=[]
for l in lines:
    p=l.split('\t')
    if len(p)!=3: 
        print("BAD",repr(l)); continue
    rows.append(p)

# analyze relationship lemma->form per feature
def analyze(lemma,form):
    # find how form relates: prefix + lemma + suffix?
    if lemma in form:
        i=form.index(lemma)
        pre=form[:i]; suf=form[i+len(lemma):]
        return ('CONTAIN',pre,suf)
    return ('OTHER',lemma,form)

pats=defaultdict(lambda: defaultdict(int))
examples=defaultdict(list)
for lemma,form,feat in rows:
    typ,pre,suf=analyze(lemma,form)
    pats[feat][(typ,pre,suf)]+=1
    if len(examples[(feat,typ,pre,suf)])<3:
        examples[(feat,typ,pre,suf)].append((lemma,form))

for feat in sorted(pats):
    print("====",feat)
    for k,c in sorted(pats[feat].items(),key=lambda x:-x[1]):
        print(f"  {c:4d}  pre={k[1]!r} suf={k[2]!r} type={k[0]}  ex={examples[(feat,)+k][:2]}")
EOF

