rows=[l.rstrip('\n').split('\t') for l in open('kon.trn')]
# determine ku vs ko per lemma from NFIN and FUT
ko_lemmas=set(); ku_lemmas=set()
for lemma,form,feat in rows:
    if feat=='V;NFIN':
        if form.startswith('ku'): ku_lemmas.add(lemma)
        elif form.startswith('ko'): ko_lemmas.add(lemma)
    if feat=='V;FUT':
        if form.startswith('ta ku'): ku_lemmas.add(lemma)
        elif form.startswith('ta ko'): ko_lemmas.add(lemma)
print("KO lemmas:",sorted(ko_lemmas))
print("num ku lemmas:",len(ku_lemmas))
# conflicts?
print("conflict:",ko_lemmas & ku_lemmas)
# check vowels in ko lemmas
for l in sorted(ko_lemmas): print(" ",l)
